import{_ as a,o as t,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"62. Casual Employment Caring Responsibilities","description":"","frontmatter":{"title":"62. Casual Employment Caring Responsibilities","eba":"Nurses and Midwives 2024-2028","topics":["leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/62-casual-employment-caring-responsibilities.md","filePath":"ebas/nurses-midwives/leave/62-casual-employment-caring-responsibilities.md"}'),n={name:"ebas/nurses-midwives/leave/62-casual-employment-caring-responsibilities.md"};function i(r,e,l,p,m,c){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_62-casual-employment-caring-responsibilities" tabindex="-1">62. Casual Employment Caring Responsibilities <a class="header-anchor" href="#_62-casual-employment-caring-responsibilities" aria-label="Permalink to &quot;62. Casual Employment Caring Responsibilities&quot;">​</a></h1><p><strong>62.1</strong> Subject to the evidentiary and notice requirements that apply to carer&#39;s leave under clause 61.6, a casual Employee is entitled to be unavailable to attend work, or to leave work, if they need to provide care or support to a member of the Employee&#39;s Immediate family or household because of:</p><p><strong>(a)</strong> a personal illness, or personal injury, affecting them;</p><p><strong>(b)</strong> an unexpected emergency affecting them; or</p><p><strong>(c)</strong> the birth of a child.</p><p><strong>62.2</strong> The Employer and the Employee will agree on the period for which the Employee will be entitled to be unavailable to attend work. In the absence of agreement, the Employee is entitled to not be available to attend work for up to two days per occasion, which may be</p><p>taken as a single continuous period of up to two days or any separate periods to which the Employer and Employer agree.</p><p><strong>62.3</strong> The casual Employee is not entitled to any payment for the period of non-attendance.</p><p><strong>62.4</strong> An Employer must not fail to re-engage a casual Employee because the Employee accessed the entitlements provided for in this clause. The rights of an Employer to engage or not to engage a casual Employee are otherwise not affected.</p><p>Plain language terms: casuals, casual work, casual rate.</p>',10)])])}const g=a(n,[["render",i]]);export{u as __pageData,g as default};
